from sqlalchemy import Column, Integer, String, case, func
from sqlalchemy.ext.hybrid import hybrid_property, hybrid_method
from sqlalchemy.orm import declarative_base, Session

Base = declarative_base()

class User(Base):
    __tablename__ = 'users'
    id = Column(Integer, primary_key=True)
    first_name = Column(String(50))
    last_name = Column(String(50))
    salary = Column(Integer)

    # Hybrid property: full_name
    @hybrid_property
    def full_name(self):
        """Python-level: concatenate strings."""
        return f"{self.first_name} {self.last_name}"

    @full_name.expression
    def full_name(cls):
        """SQL-level: use || or concat."""
        return cls.first_name + ' ' + cls.last_name

    # Hybrid property with setter
    @hybrid_property
    def email_lower(self):
        return self._email.lower() if self._email else None

    # Hybrid property for status
    @hybrid_property
    def salary_tier(self):
        if self.salary >= 100000:
            return 'senior'
        elif self.salary >= 50000:
            return 'mid'
        return 'junior'

    @salary_tier.expression
    def salary_tier(cls):
        return case(
            (cls.salary >= 100000, 'senior'),
            (cls.salary >= 50000, 'mid'),
            else_='junior'
        )

# Usage in queries
with Session(engine) as session:
    # Filter using hybrid property (generates SQL)
    user = session.query(User).filter(User.full_name == 'John Doe').first()

    # Order by hybrid property
    users = session.query(User).order_by(User.full_name).all()

    # Filter by salary tier
    seniors = session.query(User).filter(User.salary_tier == 'senior').all()

    # Use on an instance (runs Python)
    user = session.query(User).first()
